// Define the function
function greet(name) {
  // name is a parameter — it acts like a variable
  return 'Hello, ' + name + '!';
}

// Call the function with different arguments
let message1 = greet('Alice');
console.log(message1);
// Expected output: Hello, Alice!

let message2 = greet('Bob');
console.log(message2);
// Expected output: Hello, Bob!

// Function with two parameters
function add(a, b) {
  return a + b;
}
console.log(add(5, 3));
// Expected output: 8
